import json
from typing import Dict, Any
import pandas as pd

def valores_dcff(data):
    inds = data.get("indicators", {})
    rows = []
    for ind, locs in data.get("values", {}).items():
        if isinstance(locs, dict):
            for loc, yrs in locs.items():
                if isinstance(yrs, dict):
                    ind_name = inds.get(ind, {}).get("label", ind)
                    year = int(list(yrs.keys())[0])
                    for yr, v in yrs.items():
                        rows.append({"location_code": loc, "indicator_code": ind, "indicator_name": ind_name, "year": year, "value": float(v)})
    return pd.DataFrame(rows).dropna(subset=["location_code","indicator_code","year","value"])
